import{_ as e,o,c as a,a2 as r}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"能力圈 Circle of Competence","description":"知道自己知道什么，比知道什么更重要","frontmatter":{"title":"能力圈 Circle of Competence","description":"知道自己知道什么，比知道什么更重要"},"headers":[],"relativePath":"02_concepts/circle-of-competence.md","filePath":"02_concepts/circle-of-competence.md"}'),l={name:"02_concepts/circle-of-competence.md"};function n(c,t,i,s,u,d){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="能力圈-circle-of-competence" tabindex="-1">能力圈 Circle of Competence <a class="header-anchor" href="#能力圈-circle-of-competence" aria-label="Permalink to &quot;能力圈 Circle of Competence&quot;">​</a></h1><hr><h2 id="核心出处" tabindex="-1">核心出处 <a class="header-anchor" href="#核心出处" aria-label="Permalink to &quot;核心出处&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">重点内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>1996年</strong></td><td style="text-align:left;">能力圈边界的经典定义</td></tr><tr><td style="text-align:left;"><strong>1999年</strong></td><td style="text-align:left;">不投资科技股的逻辑：不在能力圈内</td></tr><tr><td style="text-align:left;"><strong>2000年</strong></td><td style="text-align:left;">互联网泡沫中坚守能力圈</td></tr><tr><td style="text-align:left;"><strong>2003年</strong></td><td style="text-align:left;">银行股投资：能力圈内的判断</td></tr><tr><td style="text-align:left;"><strong>2017年</strong></td><td style="text-align:left;">能力圈与&quot;五大赢家&quot;</td></tr></tbody></table><hr><h2 id="核心定义" tabindex="-1">核心定义 <a class="header-anchor" href="#核心定义" aria-label="Permalink to &quot;核心定义&quot;">​</a></h2><p>能力圈是巴菲特投资哲学中最朴素也最重要的原则之一。它指的是投资者真正理解的行业、企业和资产的边界。巴菲特从不掩饰自己的无知——他坦然承认许多领域他看不懂，这恰恰是他持续成功的关键。</p><blockquote><p>&quot;你不必成为每一家公司或者许多公司的专家。你只需要能够评估你能力范围内的公司。能力圈的大小不重要，知道它的边界在哪里才是关键。&quot;<br> ——沃伦·巴菲特，1996年致股东信</p></blockquote><h2 id="边界比规模更重要" tabindex="-1">边界比规模更重要 <a class="header-anchor" href="#边界比规模更重要" aria-label="Permalink to &quot;边界比规模更重要&quot;">​</a></h2><p>巴菲特常用一个圆来比喻：圈内是你真正懂的，圈外是你不懂的。重要的不是这个圆有多大，而是<strong>你是否诚实地知道圆的边界在哪里</strong>。</p><blockquote><p>&quot;关键是知道你的能力圈边界。有些人能够准确地评估一二百家企业；有些人只会评估少数几家企业。无论哪种方式，如果你知道自己的边界在哪里，你就会做得很好。&quot;<br> ——沃伦·巴菲特，1996年伯克希尔年度股东大会</p></blockquote><p>他在多个场合强调，在能力圈边界之外行动，比待在圈内危险得多。</p><blockquote><p>&quot;如果你在船上凿了个洞，你游得再快也没用。我们坚持只在我们有充分信心的领域投资。&quot;<br> ——沃伦·巴菲特</p></blockquote><h2 id="为什么要画清边界" tabindex="-1">为什么要画清边界 <a class="header-anchor" href="#为什么要画清边界" aria-label="Permalink to &quot;为什么要画清边界&quot;">​</a></h2><h3 id="_1-避免致命的傲慢" tabindex="-1">1. 避免致命的傲慢 <a class="header-anchor" href="#_1-避免致命的傲慢" aria-label="Permalink to &quot;1. 避免致命的傲慢&quot;">​</a></h3><p>投资市场中最危险的情绪是&quot;过度自信&quot;。一个人在某个领域取得成功后，往往会误以为自己在所有领域都有天赋。巴菲特对此保持高度警惕。</p><blockquote><p>&quot;对大多数投资者来说，最重要的不是他们知道多少，而是他们实际上如何界定自己不知道多少。能够区分何时何地是危险的，显然是帮助你生存的因素之一。&quot;<br> ——沃伦·巴菲特，1992年致股东信</p></blockquote><h3 id="_2-专注带来优势" tabindex="-1">2. 专注带来优势 <a class="header-anchor" href="#_2-专注带来优势" aria-label="Permalink to &quot;2. 专注带来优势&quot;">​</a></h3><p>在你真正理解的领域里，你会比市场看得更清楚，从而形成信息优势。</p><blockquote><p>&quot;你需要的是非常集中的兴趣和正确的信息。坐在你能力圈内、非常了解的公司旁边，比坐在不了解的公司旁边好得多。&quot;<br> ——沃伦·巴菲特，1997年伯克希尔年度股东大会</p></blockquote><h3 id="_3-减少犯错的概率" tabindex="-1">3. 减少犯错的概率 <a class="header-anchor" href="#_3-减少犯错的概率" aria-label="Permalink to &quot;3. 减少犯错的概率&quot;">​</a></h3><p>投资中每一次亏损，几乎都发生在能力圈之外。承认无知是减少永久性损失最有效的方式。</p><blockquote><p>&quot;如果你知道你在什么地方是有能力的，并且坚守这一领域，赔钱的概率就会大大降低。&quot;<br> ——沃伦·巴菲特</p></blockquote><h2 id="能力圈是如何形成的" tabindex="-1">能力圈是如何形成的 <a class="header-anchor" href="#能力圈是如何形成的" aria-label="Permalink to &quot;能力圈是如何形成的&quot;">​</a></h2><p>巴菲特的能力圈不是一天建成的。他从十几岁开始研究股票，花了数十年时间深入阅读财务报表、行业报告和商业历史。这种积累使他对消费品牌、保险和金融等行业形成了深刻的理解。</p><p>他对科技股长期持谨慎态度，不是因为看不起科技，而是因为他清楚地认识到自己在判断科技变革速度方面的局限。直到后来他才在苹果身上找到了自己能够理解的角度——这不是技术公司，而是一家拥有强大品牌忠诚度的消费公司。</p><blockquote><p>&quot;我更倾向于把苹果视为一家消费品公司，而不是一家科技公司。我能理解它的消费者行为，这是最重要的。&quot;<br> ——沃伦·巴菲特，2018年</p></blockquote><h2 id="诚实面对自己" tabindex="-1">诚实面对自己 <a class="header-anchor" href="#诚实面对自己" aria-label="Permalink to &quot;诚实面对自己&quot;">​</a></h2><p>巴菲特最令人敬佩的品质之一，是他始终对公众承认自己&quot;不知道什么&quot;。</p><blockquote><p>&quot;我们有很多内部讨论，芒格和我花大量时间坐在那里说&#39;不，我们不理解这个。&#39;我想说的是，对我们来说，最重要的不是我们做了什么，而是我们没有做什么。&quot;<br> ——沃伦·巴菲特，伯克希尔哈撒韦，1998年</p></blockquote><p>他还打过一个经典的比喻：</p><blockquote><p>&quot;作为一个投资者，如果你的能力圈里没有一家公司，那你就拥有了这个世界上最无聊的爱好。但如果你能在你的能力圈内找到一些公司，并且真正理解它们，你就已经走在正确的道路上了。&quot;<br> ——沃伦·巴菲特</p></blockquote><h2 id="对普通投资者的启示" tabindex="-1">对普通投资者的启示 <a class="header-anchor" href="#对普通投资者的启示" aria-label="Permalink to &quot;对普通投资者的启示&quot;">​</a></h2><ol><li><strong>不要假装全能</strong>——没有人能看懂所有行业。承认这一点不是弱点，而是智慧的开始。</li><li><strong>持续深耕自己的能力圈</strong>——在你感兴趣且能理解的领域不断积累知识。</li><li><strong>遇到不懂的机会就放弃</strong>——市场上永远不缺机会，缺的是耐心等待能力圈内的好机会。</li><li><strong>定期检视自己的边界</strong>——市场在变化，你的能力圈也需要动态更新。</li></ol><blockquote><p>&quot;你必须弄清楚自己在哪些方面有优势，在哪些方面有劣势。那些试图成为全能选手的投资者，最终的业绩往往只是平平。&quot;<br> ——沃伦·巴菲特</p></blockquote><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>能力圈原则的本质是<strong>诚实的自我认知</strong>。知道自己知道什么，比知道什么更重要。巴菲特的整个投资生涯都在践行这一原则——他不是没有错过机会，而是他很少在自己不理解的领域里冒险。</p><p>这才是长期制胜的关键：<strong>不是扩大能力圈的半径，而是永远忠实于它的边界。</strong></p>',38)])])}const p=e(l,[["render",n]]);export{q as __pageData,p as default};
